import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"恭王府","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/gongwangfu.md","filePath":"landmarks/gongwangfu.md","lastUpdated":1784773307000}'),n={name:"landmarks/gongwangfu.md"};function o(d,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="恭王府" tabindex="-1">恭王府 <a class="header-anchor" href="#恭王府" aria-label="Permalink to &quot;恭王府&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-BGZj9K41kOo?w=1200" alt="恭王府"></p><blockquote><p>&quot;一座恭王府，半部清代史。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>恭王府位于北京市西城区前海西街17号，是清代规模最大的一座王府，也是现存最完整的清代王府建筑群。恭王府始建于清乾隆年间，最初为和珅的宅邸，后成为恭亲王奕訢的府邸，见证了大清王朝从鼎盛走向衰落的历史进程。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-17:00（旺季），9:00-16:00（淡季），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">40元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6号线北海北站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区前海西街17号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="和珅宅邸时期-1777-1799" tabindex="-1">和珅宅邸时期（1777-1799） <a class="header-anchor" href="#和珅宅邸时期-1777-1799" aria-label="Permalink to &quot;和珅宅邸时期（1777-1799）&quot;">​</a></h3><p>清乾隆四十一年（1776年），和珅开始在此营建宅邸。和珅是乾隆皇帝的宠臣，权倾朝野，其宅邸的奢华程度仅次于皇宫。</p><h4 id="建筑规模" tabindex="-1">建筑规模 <a class="header-anchor" href="#建筑规模" aria-label="Permalink to &quot;建筑规模&quot;">​</a></h4><ul><li><strong>占地面积</strong>：约6万平方米</li><li><strong>建筑面积</strong>：约3万平方米</li><li><strong>房屋数量</strong>：约1000间</li><li><strong>花园面积</strong>：约2.8万平方米</li></ul><h3 id="庆王府时期-1799-1851" tabindex="-1">庆王府时期（1799-1851） <a class="header-anchor" href="#庆王府时期-1799-1851" aria-label="Permalink to &quot;庆王府时期（1799-1851）&quot;">​</a></h3><p>嘉庆四年（1799年），和珅被赐死，家产被抄，宅邸被赐给庆郡王永璘。</p><h3 id="恭王府时期-1851-1912" tabindex="-1">恭王府时期（1851-1912） <a class="header-anchor" href="#恭王府时期-1851-1912" aria-label="Permalink to &quot;恭王府时期（1851-1912）&quot;">​</a></h3><p>咸丰元年（1851年），咸丰帝将这座宅邸赐给恭亲王奕訢，从此称为&quot;恭王府&quot;。恭亲王奕是道光帝第六子，洋务运动的主要领导者之一。</p><h4 id="恭亲王奕訢" tabindex="-1">恭亲王奕訢 <a class="header-anchor" href="#恭亲王奕訢" aria-label="Permalink to &quot;恭亲王奕訢&quot;">​</a></h4><p>奕訢是晚清政坛的核心人物，曾任总理衙门大臣、军机大臣等要职，主导了洋务运动。</p><h3 id="近代变迁-1912-至今" tabindex="-1">近代变迁（1912-至今） <a class="header-anchor" href="#近代变迁-1912-至今" aria-label="Permalink to &quot;近代变迁（1912-至今）&quot;">​</a></h3><p>民国时期，恭王府先后成为辅仁大学女部、中国艺术研究院等机构的所在地。1982年被列为全国重点文物保护单位，2008年全面对外开放。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>恭王府由府邸和花园两部分组成，整体布局呈&quot;前府后园&quot;的格局。</p><h3 id="府邸部分" tabindex="-1">府邸部分 <a class="header-anchor" href="#府邸部分" aria-label="Permalink to &quot;府邸部分&quot;">​</a></h3><h4 id="银安殿" tabindex="-1">银安殿 <a class="header-anchor" href="#银安殿" aria-label="Permalink to &quot;银安殿&quot;">​</a></h4><p>银安殿是恭王府的正殿，也是王府中最重要的建筑。殿内原设有亲王宝座，是举行重大礼仪活动的场所。</p><ul><li><strong>建筑形制</strong>：重檐歇山顶</li><li><strong>面阔</strong>：五间</li><li><strong>功能</strong>：举行礼仪、接见宾客</li></ul><h4 id="多福轩" tabindex="-1">多福轩 <a class="header-anchor" href="#多福轩" aria-label="Permalink to &quot;多福轩&quot;">​</a></h4><p>多福轩是恭亲王日常起居和处理政务的地方。轩内悬挂着&quot;多福&quot;匾额，寓意多福多寿。</p><h4 id="乐道堂" tabindex="-1">乐道堂 <a class="header-anchor" href="#乐道堂" aria-label="Permalink to &quot;乐道堂&quot;">​</a></h4><p>乐道堂是恭亲王的书房，也是他处理政务、读书写字的地方。堂内收藏有大量珍贵文物。</p><h3 id="花园部分" tabindex="-1">花园部分 <a class="header-anchor" href="#花园部分" aria-label="Permalink to &quot;花园部分&quot;">​</a></h3><p>恭王府花园又名&quot;萃锦园&quot;，是王府的精华所在。</p><h4 id="西洋门" tabindex="-1">西洋门 <a class="header-anchor" href="#西洋门" aria-label="Permalink to &quot;西洋门&quot;">​</a></h4><p>西洋门是花园的正门，采用汉白玉石拱门，具有典型的西洋建筑风格，是恭王府花园的标志性建筑。</p><h4 id="大戏楼" tabindex="-1">大戏楼 <a class="header-anchor" href="#大戏楼" aria-label="Permalink to &quot;大戏楼&quot;">​</a></h4><p>恭王府大戏楼是北京现存最完整的王府戏楼，可容纳200余人观戏。戏楼建筑精美，音响效果极佳。</p><h4 id="福字碑" tabindex="-1">福字碑 <a class="header-anchor" href="#福字碑" aria-label="Permalink to &quot;福字碑&quot;">​</a></h4><p>福字碑是康熙皇帝的御笔，被誉为&quot;天下第一福&quot;。这个&quot;福&quot;字包含了&quot;子、才、田、福、寿&quot;五个字，寓意五福临门。</p><h4 id="滴翠岩" tabindex="-1">滴翠岩 <a class="header-anchor" href="#滴翠岩" aria-label="Permalink to &quot;滴翠岩&quot;">​</a></h4><p>滴翠岩是花园中的假山，由太湖石堆砌而成。假山内有秘云洞，洞内有福字碑。</p><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">特色</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>西洋门</strong></td><td style="text-align:left;">汉白玉拱门，西洋风格</td><td style="text-align:left;">拍照打卡圣地</td></tr><tr><td style="text-align:left;"><strong>大戏楼</strong></td><td style="text-align:left;">北京最完整的王府戏楼</td><td style="text-align:left;">听戏体验</td></tr><tr><td style="text-align:left;"><strong>福字碑</strong></td><td style="text-align:left;">康熙御笔&quot;天下第一福&quot;</td><td style="text-align:left;">祈福纳祥</td></tr><tr><td style="text-align:left;"><strong>滴翠岩</strong></td><td style="text-align:left;">太湖石假山</td><td style="text-align:left;">园林造景精品</td></tr><tr><td style="text-align:left;"><strong>邀月台</strong></td><td style="text-align:left;">赏月胜地</td><td style="text-align:left;">中秋赏月</td></tr><tr><td style="text-align:left;"><strong>方塘水榭</strong></td><td style="text-align:left;">水景园林</td><td style="text-align:left;">夏日纳凉</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约2小时）</strong>：</p><p>正门 → 银安殿 → 多福轩 → 乐道堂 → 西洋门 → 大戏楼 → 滴翠岩（福字碑） → 方塘水榭 → 邀月台 → 出口</p><p><strong>深度路线（约3小时）</strong>：</p><p>正门 → 银安殿 → 多福轩 → 乐道堂 → 锡晋斋 → 后罩楼 → 西洋门 → 大戏楼 → 滴翠岩（福字碑） → 方塘水榭 → 邀月台 → 牡丹园 → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：恭王府实行预约制，建议提前在官网或微信公众号预约</li><li><strong>最佳时间</strong>：工作日人流较少，上午9点前入园最佳</li><li><strong>福字碑</strong>：排队人很多，建议一入园先去排福字碑</li><li><strong>拍照位置</strong>：西洋门、大戏楼前、方塘水榭都是绝佳拍照点</li><li><strong>讲解服务</strong>：建议租用讲解器或请导游，了解更多历史故事</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">6号线北海北站B口，步行约10分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">13、42、107、111、118路北海北门站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;恭王府&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京胡同水乡</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">俯瞰紫禁城</td></tr><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">网红胡同</td></tr><tr><td style="text-align:left;">后海酒吧街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">夜生活</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>恭王府是清代王府建筑的典范，也是研究清代政治、文化、建筑的重要实物资料。从和珅的奢靡到恭亲王的洋务，这座王府见证了大清王朝最后的风云变幻。</p><p>&quot;一座恭王府，半部清代史&quot;，这句话形象地概括了恭王府在中国历史上的重要地位。</p><hr><p><strong>📍 地址</strong>：北京市西城区前海西街17号 ** 地铁**：6号线北海北站B口 <strong>📞 电话</strong>：010-83288149 <strong>🌐 官网</strong>：<a href="http://www.pgm.org.cn" target="_blank" rel="noreferrer">www.pgm.org.cn</a></p><p><strong>💡 Tips</strong>：恭王府的福字碑是必打卡的景点，摸一摸&quot;福&quot;字，沾沾福气！</p>',60)])])}const u=e(n,[["render",o]]);export{x as __pageData,u as default};
